import numpy as np

def value_backup(reward, next_values):
    reward = np.asarray(reward, dtype=np.float64)
    next_values = np.asarray(next_values, dtype=np.float64)
    gamma = 0.9
    return np.max(reward + gamma * next_values, axis=1)
